code = """import json
import re
import pandas as pd

# Load data
with open('file_storage/functions.query_db:6.json', 'r') as f:
    funding_data = json.load(f)

with open('file_storage/functions.query_db:10.json', 'r') as f:
    civic_docs = json.load(f)

funding_df = pd.DataFrame(funding_data)
funding_df['Amount'] = pd.to_numeric(funding_df['Amount'])

# Extract projects with Spring 2022 start dates
spring_2022_projects = []

for doc in civic_docs:
    text = doc['text']
    lines = text.split('\n')
    
    i = 0
    while i < len(lines):
        line = lines[i].strip()
        
        # Skip empty lines and headers
        if not line or any(skip in line for skip in ['Page', 'Agenda Item', 'To:', 'Prepared by:', 'Approved by:', 'Date prepared:', 'Meeting date:', 'Subject:', 'RECOMMENDED ACTION:', 'DISCUSSION:']):
            i += 1
            continue
        
        # Look for project name patterns
        project_name = None
        
        # Pattern 1: Year + Project Name (e.g., "2022 Morning View Resurfacing")
        if re.match(r'^\d{4}\s+[A-Z][a-zA-Z\s&\-/]+$', line) and len(line) > 15:
            project_name = line
            # Check if next lines have Spring 2022
            for j in range(i+1, min(i+8, len(lines))):
                if '2022' in lines[j] and ('Spring' in lines[j] or 'spring' in lines[j]):
                    start_date = '2022-Spring'
                    spring_2022_projects.append({
                        'Project_Name': project_name,
                        'start_date': start_date,
                        'doc_id': doc['_id']
                    })
                    break
        
        # Pattern 2: Project name with FEMA/CalOES suffix
        elif re.search(r'\((FEMA|CalOES|CalJPIA|FEMA/CalOES)\s+Project\)', line) and len(line) > 15:
            project_name = line
            for j in range(i+1, min(i+8, len(lines))):
                if '2022' in lines[j] and ('Spring' in lines[j] or 'spring' in lines[j]):
                    start_date = '2022-Spring'
                    spring_2022_projects.append({
                        'Project_Name': project_name,
                        'start_date': start_date,
                        'doc_id': doc['_id']
                    })
                    break
        
        # Pattern 3: Regular project names (title case, descriptive)
        elif (len(line) > 15 and not line.isupper() and 
              re.match(r'^[A-Z][a-zA-Z\s&\-/]+$', line) and
              len(line.split()) > 2 and
              not any(keyword in line for keyword in ['Capital Improvement', 'Disaster Recovery', 'Project Schedule', 'Updates:', 'Project Description'])):
            
            # Look ahead for schedule info
            for j in range(i+1, min(i+10, len(lines))):
                next_line = lines[j].strip()
                
                # Look for Spring 2022 in schedule
                if '2022' in next_line and ('Spring' in next_line or 'spring' in next_line):
                    # Check if this is an action date (Begin, Complete Design, etc.)
                    if any(action in next_line for action in ['Begin', 'Complete Design', 'Start', 'Advertise', 'Award']):
                        project_name = line
                        start_date = '2022-Spring'
                        spring_2022_projects.append({
                            'Project_Name': project_name,
                            'start_date': start_date,
                            'doc_id': doc['_id']
                        })
                        break
        
        i += 1

# Create DataFrame of Spring 2022 projects
spring_df = pd.DataFrame(spring_2022_projects)

# Remove duplicates
spring_df = spring_df.drop_duplicates(subset=['Project_Name'])

print('__RESULT__:')
print(json.dumps({
    "spring_2022_projects_count": len(spring_df),
    "sample_projects": spring_df['Project_Name'].head(10).tolist() if not spring_df.empty else []
}))"""

